// ============================================================
// GERCEK DOGRULUK BENCHMARK'I
// Metodoloji notu: tool secimi dogrulugu icin "exact match"
// (Berkeley Function-Calling Leaderboard AST-match yaklasimina benzer),
// geocoding dogrulugu icin "X km esik degeri icinde mi" yaklasimi
// (yaygin geocoding-benchmark literaturunde kullanilan esik tabanli dogruluk).
// ============================================================

const BASE_URL = ($json.body && $json.body.base_url) || 'http://localhost:5678/webhook';

const testCases = [
  { query: "Zeytinburnu'ndaki eczanelerin etrafina 200m buffer at", expected_tool: "Buffer", location: "Zeytinburnu", lat: 40.9950, lon: 28.9020, feature_type: "pharmacy", distance: 200 },
  { query: "Kadikoy'deki kafeleri goster", expected_tool: "AttributeTable", location: "Kadikoy", lat: 40.9833, lon: 29.0333, feature_type: "cafe" },
  { query: "Besiktas'taki hastanelerin oznitelik tablosunu ac", expected_tool: "AttributeTable", location: "Besiktas", lat: 41.0422, lon: 29.0061, feature_type: "hospital" },
  { query: "Uskudar'da adinda Merkez gecen eczaneleri bul", expected_tool: "AttributeQuery", location: "Uskudar", lat: 41.0226, lon: 29.0244, feature_type: "pharmacy", filter_field: "name" },
  { query: "Sisli'deki eczanelere en yakin hastaneyi bul", expected_tool: "NearestSearch", location: "Sisli", lat: 41.0608, lon: 28.9866, feature_type: "pharmacy", secondary_feature_type: "hospital" },
  { query: "Fatih'teki okullarin yogunluk analizini yap", expected_tool: "PointDensity", location: "Fatih", lat: 41.0190, lon: 28.9495, feature_type: "school" },
  { query: "Beyoglu'nu haritada goster", expected_tool: "Geocode", location: "Beyoglu", lat: 41.0370, lon: 28.9850 },
  { query: "Maltepe'deki parklarin 300 metre etki alanini ciz", expected_tool: "Buffer", location: "Maltepe", lat: 40.9357, lon: 29.1517, feature_type: "park", distance: 300 },
  { query: "Bahcelievler'deki eczanelerin 400m bufferi ile okullarin 300m bufferinin kesisimini bul", expected_tool: "Intersection", location: "Bahcelievler", lat: 41.0036, lon: 28.8631, feature_type: "pharmacy", secondary_feature_type: "school", distance: 400, secondary_distance: 300 },
  { query: "Atasehir'deki bankalari listele", expected_tool: "AttributeTable", location: "Atasehir", lat: 40.9923, lon: 29.1244, feature_type: "bank" }
];

const models = [
  { key: 'claude',   path: 'gis-claude' },
  { key: 'gpt',      path: 'gis-gpt' },
  { key: 'groq',     path: 'gis-groq' },
  { key: 'gemini',   path: 'gis-gemini' },
  { key: 'deepseek', path: 'gis-deepseek' },
  { key: 'qwen',     path: 'gis-qwen' },
  { key: 'kimi',     path: 'gis-kimi' },
  { key: 'glm',      path: 'gis-glm' }
];

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

const GEO_THRESHOLD_KM = 2; // 2 km icinde ise konum bulma "dogru" sayilir

const perModelResults = {};
for (const m of models) perModelResults[m.key] = [];

for (const tc of testCases) {
  for (const m of models) {
    const t0 = Date.now();
    let resp = null, error = null;
    try {
      resp = await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/${m.path}`,
        body: { message: tc.query },
        json: true,
        timeout: 60000
      });
    } catch (e) {
      error = e.message || String(e);
    }
    const wallMs = Date.now() - t0;

    const row = { query: tc.query, expected_tool: tc.expected_tool, error };
    if (resp) {
      const p = resp.parameters || {};
      row.actual_tool = resp.selected_tool;
      row.tool_match = resp.selected_tool === tc.expected_tool ? 1 : 0;

      if (tc.feature_type) {
        row.feature_type_match = (p.feature_type === tc.feature_type) ? 1 : 0;
      }
      if (tc.distance) {
        row.distance_match = (Number(p.distance_meters) === Number(tc.distance)) ? 1 : 0;
      }
      if (typeof p.latitude === 'number' && typeof p.longitude === 'number') {
        const distKm = haversineKm(p.latitude, p.longitude, tc.lat, tc.lon);
        row.geocode_distance_km = Math.round(distKm * 100) / 100;
        row.geocode_correct = distKm <= GEO_THRESHOLD_KM ? 1 : 0;
      } else {
        row.geocode_correct = 0;
      }
      row.schema_valid = (resp.geojson && resp.geojson.type === 'FeatureCollection') ? 1 : 0;
      row.processing_time_ms = resp.processing_time_ms ?? wallMs;
      row.feature_count = resp.feature_count ?? 0;
    } else {
      row.tool_match = 0;
      row.geocode_correct = 0;
      row.schema_valid = 0;
      row.processing_time_ms = wallMs;
      row.feature_count = 0;
    }
    perModelResults[m.key].push(row);
  }
}

// --- Aggregation: gercek olcumlere dayali skorlar ---
function avg(arr) { return arr.length ? arr.reduce((a,b)=>a+b,0) / arr.length : 0; }

const dashboard = {};
for (const m of models) {
  const rows = perModelResults[m.key];
  const paramRows = rows.filter(r => r.feature_type_match !== undefined || r.distance_match !== undefined);
  const paramScores = paramRows.map(r => {
    const parts = [];
    if (r.feature_type_match !== undefined) parts.push(r.feature_type_match);
    if (r.distance_match !== undefined) parts.push(r.distance_match);
    return avg(parts);
  });

  dashboard[m.key] = {
    tool_accuracy: Math.round(avg(rows.map(r => r.tool_match)) * 100),
    spatial_accuracy: Math.round(avg(rows.map(r => r.geocode_correct)) * 100),
    param_accuracy: Math.round(avg(paramScores) * 100),
    schema_validity: Math.round(avg(rows.map(r => r.schema_valid)) * 100),
    avg_latency_ms: Math.round(avg(rows.map(r => r.processing_time_ms))),
    error_count: rows.filter(r => r.error).length,
    details: rows
  };
}

return [{
  json: {
    generated_at: new Date().toISOString(),
    test_case_count: testCases.length,
    methodology: {
      tool_accuracy: "Beklenen GIS aracinin (selected_tool) tam eslesme orani (Berkeley Function-Calling Leaderboard AST-match yaklasimi)",
      spatial_accuracy: `Nominatim'den donen koordinatin gercek konuma ${GEO_THRESHOLD_KM} km icinde olma orani`,
      param_accuracy: "feature_type ve distance_meters parametrelerinin dogru cikarilma orani",
      schema_validity: "Cikan GeoJSON'un gecerli FeatureCollection olma orani"
    },
    dashboard
  }
}];
